const eventos = ['click', 'keydown', 'mouseover', 'keyup', 'input', 'keypress'];
const eventosTeclado = ['keydown', 'keyup', 'keypress'];

const soloTeclado = eventos.filter(e => eventosTeclado.includes(e));

function crearEmisor() {
  const manejadores = {};

  return {
    on(evento, fn) {
      if (!manejadores[evento]) manejadores[evento] = [];
      manejadores[evento].push(fn);
    },
    emit(evento) {
      if (manejadores[evento]) {
        manejadores[evento].forEach(fn => fn());
      }
    }
  };
}

const emisor = crearEmisor();
const registro = [];

emisor.on('click', () => registro.push('primer listener'));
emisor.on('click', () => registro.push('segundo listener'));
emisor.emit('click');

function crearContador() {
  let valor = 0;

  return {
    incrementar() {
      valor += 1;
    },
    obtenerValor() {
      return valor;
    },
    reiniciar() {
      valor = 0;
    }
  };
}

const contador = crearContador();
